from langchain_core.documents import Document

def filter_relevant(question: str, docs: list[Document]) -> list[Document]:
    relevant = []
    for doc in docs:
        prompt = (
            f"Question: {question}\n\n"
            f"Document excerpt:\n{doc.page_content}\n\n"
            "Is this document relevant to the question? Answer RELEVANT or IRRELEVANT only."
        )
        verdict = llm.invoke(prompt).content.strip().upper()
        if "RELEVANT" in verdict:
            relevant.append(doc)
    return relevant

from langchain_community.vectorstores import FAISS
from langchain_openai import OpenAIEmbeddings

embedder = OpenAIEmbeddings(model="text-embedding-3-small")
store = FAISS.load_local("./index", embedder, allow_dangerous_deserialization=True)

def retrieve_and_filter(question: str, k: int = 5) -> list[Document]:
    candidates = store.similarity_search(question, k=k)
    return filter_relevant(question, candidates)

from dataclasses import dataclass

@dataclass
class Candidate:
    doc: Document
    answer: str
    support_score: int   # 0, 1, or 2 (no support, partial, full)
    utility_score: int   # 1-5

def generate_candidate(question: str, doc: Document) -> Candidate:
    # Generate answer conditioned on this document
    gen_prompt = (
        f"Document:\n{doc.page_content}\n\n"
        f"Question: {question}\n\n"
        "Answer the question using only the information in the document above."
    )
    answer = llm.invoke(gen_prompt).content.strip()

    # Score faithfulness (ISSUP)
    sup_prompt = (
        f"Document:\n{doc.page_content}\n\n"
        f"Generated answer:\n{answer}\n\n"
        "Is the generated answer fully supported by the document?"
        " Answer: FULLY_SUPPORTED, PARTIALLY_SUPPORTED, or NOT_SUPPORTED."
    )
    sup_verdict = llm.invoke(sup_prompt).content.strip().upper()
    if "FULLY" in sup_verdict:
        support_score = 2
    elif "PARTIALLY" in sup_verdict:
        support_score = 1
    else:
        support_score = 0

    # Score utility (ISUSE)
    use_prompt = (
        f"Question: {question}\n\n"
        f"Answer:\n{answer}\n\n"
        "How useful is this answer for the user? Rate 1-5 where 5 is most useful."
        " Reply with only the number."
    )
    try:
        utility_score = int(llm.invoke(use_prompt).content.strip())
    except ValueError:
        utility_score = 3

    return Candidate(doc, answer, support_score, utility_score)

def self_rag(question: str, k: int = 5) -> str:
    if not should_retrieve(question):
        return llm.invoke(question).content.strip()

    relevant_docs = retrieve_and_filter(question, k=k)
    if not relevant_docs:
        return llm.invoke(question).content.strip()  # fall back

    candidates = [generate_candidate(question, doc) for doc in relevant_docs]
    # Select best by support + utility
    best = max(candidates, key=lambda c: c.support_score * 5 + c.utility_score)
    return best.answer

from langchain_openai import ChatOpenAI
from langchain_community.vectorstores import FAISS
from langchain_openai import OpenAIEmbeddings

# Lightweight evaluator to score retrieval quality
evaluator = ChatOpenAI(model="gpt-4o-mini", temperature=0)

def score_retrieved_docs(question: str, docs: list) -> float:
    """Returns 0-1 score: how well docs cover the question."""
    context = "\n\n".join(d.page_content for d in docs)
    prompt = (
        f"Question: {question}\n\n"
        f"Retrieved context:\n{context[:2000]}\n\n"
        "Score how well the context answers the question: 0.0 (not at all) to 1.0 (fully). "
        "Reply with only a number."
    )
    try:
        return float(evaluator.invoke(prompt).content.strip())
    except ValueError:
        return 0.5

def strip_irrelevant_sentences(question: str, text: str) -> str:
    prompt = (
        f"Question: {question}\n\n"
        f"Text:\n{text}\n\n"
        "Remove sentences that are NOT relevant to the question."
        " Return only the relevant sentences."
    )
    return evaluator.invoke(prompt).content.strip()

def crag(
    question: str,
    store: FAISS,
    web_search_fn=None,
    high_threshold: float = 0.7,
    low_threshold: float = 0.3,
) -> str:
    docs = store.similarity_search(question, k=5)
    score = score_retrieved_docs(question, docs)

    if score >= high_threshold:
        context = "\n\n".join(d.page_content for d in docs)
    elif score <= low_threshold:
        if web_search_fn:
            context = web_search_fn(question)  # external search fallback
        else:
            context = "\n\n".join(d.page_content for d in docs)
    else:
        refined = [
            strip_irrelevant_sentences(question, d.page_content)
            for d in docs
        ]
        context = "\n\n".join(r for r in refined if r)
        if web_search_fn:
            context += "\n\n" + web_search_fn(question)

    return generate_answer(question, [context])
